esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Task scheduler execution failure counter (cumulative)
| WHERE COALESCE(metrics.task_scheduler_total_execute_failure, task_scheduler_total_execute_failure) IS NOT NULL
// Detect increase in failures over the window
| STATS min_fail = MIN(COALESCE(metrics.task_scheduler_total_execute_failure, task_scheduler_total_execute_failure)),
    max_fail = MAX(COALESCE(metrics.task_scheduler_total_execute_failure, task_scheduler_total_execute_failure))
  BY host.name
| EVAL failure_increase = max_fail - min_fail
// Alert when any new task execution failures occurred
| WHERE failure_increase > 0
